const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.handleTelemetryMessage !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'telemetry API missing' });
  return [null, null, { payload: { error: 'TELEMETRY_API_MISSING' } }];
}

const telemetry = lib.telemetry;
const equipmentId = 'MBMU';
const state = flow.get('mbmuTelemetryState') || telemetry.createTelemetryRuntimeState();
const incoming = msg.payload && typeof msg.payload === 'object' && !Array.isArray(msg.payload)
  ? { ...msg, ...msg.payload }
  : msg;

const store = global.get('NEW_telemetry') || {};
if (!Array.isArray(store[equipmentId])) {
  store[equipmentId] = [];
  global.set('NEW_telemetry', store);
}

const asNodeRedMsg = (value) => {
  if (value == null) return null;
  if (typeof value === 'object' && !Array.isArray(value) && Object.prototype.hasOwnProperty.call(value, 'payload')) {
    return value;
  }
  return { payload: value };
};

const envCfg = {
  CompilerMaxQty: 120,
  CompilerMaxSpan: 80,
  CompilerMaxHole: 4,
  PollFastMs: 250,
  PollNormalMs: 1000,
  PollSlowMs: 5000,
  MAX_IN_FLIGHT: 8,
  REQUEST_TIMEOUT_MS: 1500,
  MODBUS_ZERO_BASED: false,
  JITTER_MS: 0,
  RESPECT_TAG_CLAMP: true,
  SCALE_CLAMP_DEFAULT: false,
  SKIP_EMPTY_SAMPLES: false
};

try {
  const result = telemetry.handleTelemetryMessage(
    incoming,
    envCfg,
    state,
    (o1, o2, o3) => node.send([asNodeRedMsg(o1), asNodeRedMsg(o2), asNodeRedMsg(o3)])
  );

  flow.set('mbmuTelemetryState', result.state);

  const statusText = incoming.cmd || (incoming._reader ? 'reply' : 'start');
  node.status({ fill: 'green', shape: 'dot', text: statusText });

  return [asNodeRedMsg(result.out1), asNodeRedMsg(result.out2), asNodeRedMsg(result.out3)];
} catch (err) {
  node.status({ fill: 'red', shape: 'ring', text: 'runtime threw' });
  return [null, null, { payload: { error: String(err) } }];
}

const equipmentName = 'MBMU';
const incoming = Array.isArray(msg.payload) ? msg.payload : [];
const store = global.get('NEW_telemetry') || {};
const current = Array.isArray(store[equipmentName]) ? store[equipmentName] : [];
const byTag = {};

const toIsoTs = (value) => {
  if (typeof value === 'string' && value.trim()) {
    const parsed = new Date(value);
    if (!Number.isNaN(parsed.getTime())) {
      return parsed.toISOString();
    }
  }
  if (typeof value === 'number' && Number.isFinite(value)) {
    return new Date(value).toISOString();
  }
  return new Date().toISOString();
};

for (const sample of current) {
  if (sample && sample.tagID) {
    byTag[sample.tagID] = sample;
  }
}

for (const sample of incoming) {
  if (!sample || !sample.tagID) continue;
  const tagID = sample.tagID.startsWith(equipmentName + '.')
    ? sample.tagID
    : equipmentName + '.' + sample.tagID;

  byTag[tagID] = {
    tagID,
    value: sample.value,
    timestamp: toIsoTs(sample.timestamp),
    alarm: sample.alarm || 'No',
    supportingTag: sample.supportingTag || 'No'
  };

  if (sample.enumLabel !== undefined) byTag[tagID].enumLabel = sample.enumLabel;
  if (sample.activeBits !== undefined) byTag[tagID].activeBits = sample.activeBits;
  if (sample.activeLabels !== undefined) byTag[tagID].activeLabels = sample.activeLabels;
  if (sample.rawValue !== undefined) byTag[tagID].rawValue = sample.rawValue;
}

store[equipmentName] = Object.values(byTag).sort((a, b) => a.tagID.localeCompare(b.tagID));
global.set('NEW_telemetry', store);

msg.payload = {
  equipment: equipmentName,
  count: store[equipmentName].length,
  NEW_telemetry: store[equipmentName]
};
return msg;

const store = global.get('NEW_telemetry') || {};
msg.payload = {
  equipment: 'MBMU',
  NEW_telemetry: Array.isArray(store.MBMU) ? store.MBMU : []
};
return msg;
